import { getOctokit } from "@actions/github";
export class GitHubClient {
    octokit;
    constructor(token) {
        this.octokit = getOctokit(token);
    }
    async collectPullRequest(pullRequest) {
        const request = {
            owner: pullRequest.owner,
            repo: pullRequest.repo,
            pull_number: pullRequest.number,
            per_page: 100,
        };
        const [commitResponses, fileResponses] = await Promise.all([
            this.octokit.paginate(this.octokit.rest.pulls.listCommits, request),
            this.octokit.paginate(this.octokit.rest.pulls.listFiles, request),
        ]);
        const commits = commitResponses.map((commit) => ({
            sha: commit.sha,
            message: commit.commit.message,
        }));
        const files = fileResponses.map((file) => ({
            filename: file.filename,
            status: file.status,
            additions: file.additions,
            deletions: file.deletions,
            changes: file.changes,
            ...(file.patch === undefined ? {} : { patch: file.patch }),
        }));
        return { pullRequest, commits, files };
    }
    async updatePullRequest(pullRequest, update) {
        await this.octokit.rest.pulls.update({
            owner: pullRequest.owner,
            repo: pullRequest.repo,
            pull_number: pullRequest.number,
            ...update,
        });
    }
    async upsertPullRequestComment(pullRequest, body) {
        const comments = await this.octokit.paginate(this.octokit.rest.issues.listComments, {
            owner: pullRequest.owner,
            repo: pullRequest.repo,
            issue_number: pullRequest.number,
            per_page: 100,
        });
        const existing = comments.find((comment) => comment.user?.type === "Bot" &&
            comment.body?.includes("<!-- prnote-action -->"));
        if (existing) {
            await this.octokit.rest.issues.updateComment({
                owner: pullRequest.owner,
                repo: pullRequest.repo,
                comment_id: existing.id,
                body,
            });
            return "updated";
        }
        await this.octokit.rest.issues.createComment({
            owner: pullRequest.owner,
            repo: pullRequest.repo,
            issue_number: pullRequest.number,
            body,
        });
        return "created";
    }
}
